package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.charset.StandardCharsets

@Singleton
class UserFilesController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serve(filename: String): Action[AnyContent] = Action {
    val file = new File(s"uploads/$filename")
    val content = Source.fromFile(file)(StandardCharsets.UTF_8).mkString
    Ok(content)
  }
}